INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '421dd561-56dd-4182-b74c-b3df6918b069',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX + Flax — Building Custom Neural Network Modules with nn.Module$escape$,
  $escape$JAX has no built-in layer abstraction — it's a pure function-transformation library. For composable model architecture, the idiomatic choice is Flax's `nn.Module`. Subclass it and decorate your `__call__` with `@nn.compact` to define parameters inline using `self.param` or `nn.Dense`, rather than in `setup()`. Activation functions live in `jax.nn` — `jax.nn.gelu`, `jax.nn.silu`, `jax.nn.relu` — all JIT-compatible and gradient-traceable. Custom modules are pure Python classes; Flax handles the pytree structure for parameter management automatically. When building deep custom blocks like residual layers, compose `nn.Module` subclasses by instantiating them as class attributes. Parameters are never mutated — `model.apply({'params': params}, x)` returns outputs functionally. This design makes it trivial to pass model state through `jax.jit`, `jax.grad`, and `jax.vmap` without side effects or hidden state bugs.$escape$,
  $escape$import jax
import jax.numpy as jnp
import flax.linen as nn

class ResidualBlock(nn.Module):
    features: int

    @nn.compact
    def __call__(self, x):
        residual = x
        x = nn.Dense(self.features)(x)
        x = jax.nn.gelu(x)
        x = nn.Dense(self.features)(x)
        return x + residual

model = ResidualBlock(features=128)
params = model.init(jax.random.PRNGKey(0), jnp.ones((4, 128)))
out = model.apply(params, jnp.ones((4, 128)))
print(out.shape)  # (4, 128)$escape$,
  $escape$python$escape$,
