INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f6cf76b9-1b21-4788-b670-8c3ffef7ff75',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Training Loop — Forward Pass, Loss, Grad, and Optimizer Step$escape$,
  $escape$JAX's training loop is built around three primitives: `jit`, `grad`, and an optax optimizer. Unlike PyTorch, there are no implicit mutable buffers — every step is a pure function that returns new state.

Define your forward pass as a plain function. Wrap loss computation with `jax.value_and_grad` to get the scalar loss and parameter gradients in a single call — no `.backward()`, no graph retention. Gradients flow through the computation trace JAX built during the forward pass.

Optimizer state (momentum buffers, adam moments) lives in an explicit `opt_state` struct managed by optax. Call `optimizer.update(grads, opt_state)` to get updates, then apply them with `optax.apply_updates(params, updates)`. Both `params` and `opt_state` are immutable PyTrees — you rebind the names each step.

Wrap the entire step function in `jax.jit` to compile it once; subsequent calls hit the XLA-compiled kernel. Shape and dtype changes will retrigger compilation, so keep your batch dimensions static or use `jax.jit` with `static_argnums`.$escape$,
  $escape$import jax, jax.numpy as jnp, optax

def loss_fn(params, x, y):
    logits = model.apply(params, x)
    return jnp.mean(optax.softmax_cross_entropy_with_integer_labels(logits, y))

@jax.jit
def train_step(params, opt_state, x, y):
    loss, grads = jax.value_and_grad(loss_fn)(params, x, y)
    updates, opt_state = optimizer.update(grads, opt_state, params)
    params = optax.apply_updates(params, updates)
    return params, opt_state, loss

optimizer = optax.adamw(learning_rate=3e-4)
opt_state = optimizer.init(params)

for x_batch, y_batch in dataloader:
    params, opt_state, loss = train_step(params, opt_state, x_batch, y_batch)$escape$,
  $escape$python$escape$,
