INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '205fa806-9c2c-49fe-9848-d4f89b73275f',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Loss Functions — Choosing the Right Loss and Writing Custom Ones$escape$,
  $escape$JAX doesn't ship a loss function library — you compose them from primitives using `jax.numpy` and differentiate with `jax.grad` or `jax.value_and_grad`. Standard losses like cross-entropy are one-liners: `jnp.mean(-jnp.sum(labels * jax.nn.log_softmax(logits), axis=-1))`. The real power comes from custom losses. Because JAX treats any pure Python function as differentiable, you can define focal loss, contrastive loss, or a physics-informed residual term and pass it directly to `jax.grad`. Crucially, custom losses must be written over a single example and vectorized with `jax.vmap` — don't manually batch inside the loss. For numerically stable implementations, prefer `jax.nn.log_softmax` over computing softmax then log separately. When combining multiple loss terms, scale them explicitly; JAX won't warn you about gradient magnitude imbalances. Use `jax.debug.print` inside loss functions during development — it works through JIT because it's treated as a side-effecting primitive, letting you inspect values without breaking the trace.$escape$,
  $escape$import jax
import jax.numpy as jnp

def focal_loss(logits, label, gamma=2.0):
    log_p = jax.nn.log_softmax(logits)
    p = jnp.exp(log_p[label])
    return -((1 - p) ** gamma) * log_p[label]

# Vectorize over a batch — never manually loop
batched_focal = jax.vmap(focal_loss, in_axes=(0, 0))

logits = jnp.ones((4, 10))
labels = jnp.array([0, 1, 2, 3])
loss_val, grads = jax.value_and_grad(
    lambda p: jnp.mean(batched_focal(p, labels))
)(logits)

print(loss_val, grads.shape)  # scalar, (4, 10)$escape$,
  $escape$python$escape$,
