INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '802042ee-8c96-4d80-ab20-22546e20b352',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Regularization — Dropout, Weight Decay, and Batch Norm Without the Magic$escape$,
  $escape$JAX gives you full control over regularization — nothing is implicit. Dropout requires explicit PRNG keys via `jax.random.bernoulli`, and you must pass a `training` flag yourself since JAX has no global mode. Weight decay is just L2 added to your loss: `loss + wd * sum(p**2 for p in leaves)` using `jax.tree_util.tree_leaves`. Batch normalization through Flax's `nn.BatchNorm` requires threading mutable state via `model.bind({'params': params, 'batch_stats': batch_stats})` and calling `module.apply(..., mutable=['batch_stats'])` during training — the updated stats come back as a second return value. Early stopping lives entirely in your training loop: track `best_val_loss`, restore a checkpointed `params` pytree with `orbax.checkpoint`. The critical insight is that JAX's functional purity means all state — dropout keys, batch statistics, best weights — must be explicitly threaded through your functions. `jax.lax.cond` lets you branch on `training` without breaking `jit` compilation.$escape$,
  $escape$import jax, jax.numpy as jnp, flax.linen as nn
from jax import random

class RegNet(nn.Module):
    @nn.compact
    def __call__(self, x, training: bool):
        x = nn.Dense(128)(x)
        x = nn.BatchNorm(use_running_average=not training)(x)
        x = nn.relu(x)
        x = nn.Dropout(rate=0.3, deterministic=not training)(x)
        return nn.Dense(10)(x)

def loss_fn(params, batch_stats, x, y, key, wd=1e-4):
    (logits, updates), mutables = model.apply(
        {'params': params, 'batch_stats': batch_stats},
        x, training=True,
        rngs={'dropout': key},
        mutable=['batch_stats']
    )
    l2 = sum(jnp.sum(p**2) for p in jax.tree_util.tree_leaves(params))
    return jnp.mean(optax.softmax_cross_entropy(logits, y)) + wd * l2, mutables$escape$,
  $escape$python$escape$,
