INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8694e5ce-3854-478d-bf5f-9069a8605caa',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Transfer Learning — stop_gradient for Freezing vs multi_transform for Fine-Tuning$escape$,
  $escape$Transfer learning in JAX pivots on two primitives: `jax.lax.stop_gradient()` for feature extraction and `optax.multi_transform` for differential fine-tuning.

Feature extraction treats the backbone as a frozen encoder — wrap its output in `jax.lax.stop_gradient()` and gradients stop flowing through it entirely. Backbone parameters still exist in the param pytree but accumulate zero gradient, so the optimizer leaves them unchanged. No mutation, no flags.

Fine-tuning needs gradients everywhere but wants the backbone to move slowly. `optax.multi_transform` accepts a `param_labels` callable that maps pytree paths to named optimizer keys. Assign `adam(1e-5)` to backbone layers and `adam(1e-3)` to the head in one composable, JIT-compatible transform.

When loading pretrained Flax weights (e.g., from HuggingFace), `flax.serialization.from_bytes` restores the full param pytree. Merge backbone params with freshly initialized head params using standard dict operations — no framework magic required. The result is a single frozen-or-trainable pytree that flows cleanly through `jax.jit`.$escape$,
  $escape$import jax, jax.numpy as jnp, optax
from flax import linen as nn

class FineTuneModel(nn.Module):
    backbone: nn.Module

    @nn.compact
    def __call__(self, x, freeze_backbone: bool = True):
        features = self.backbone(x)
        if freeze_backbone:
            features = jax.lax.stop_gradient(features)  # feature extraction
        return nn.Dense(10)(features)

# Differential LRs: backbone slow, head fast
def label_fn(path, _):
    return "backbone" if "backbone" in "/".join(path) else "head"

tx = optax.multi_transform(
    {"backbone": optax.adam(1e-5), "head": optax.adam(1e-3)},
    param_labels=label_fn,
)$escape$,
  $escape$python$escape$,
