INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c0fa9c96-45ef-414e-9ca1-a1b8a872ee94',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX Model Evaluation — Confusion Matrix, Per-Task Metrics, and Cross-Validation$escape$,
  $escape$JAX evaluates models with pure `jnp` ops, keeping everything `jit`-compilable and on-device. Build a confusion matrix using scatter-add: `jnp.zeros((C, C)).at[y_true, y_pred].add(1)` — no Python loops, no CPU round-trips. Per-class precision and recall follow directly from CM row/column slices: `tp / (cm[:, c].sum() + eps)` and `tp / (cm[c].sum() + eps)`. For regression tasks, `jnp.mean((y - y_hat) ** 2)` and `jnp.mean(jnp.abs(y - y_hat))` are trivially `jit`-compiled.

For k-fold cross-validation, avoid Python-level loops. Use `jax.vmap` over fold indices to vectorize evaluation across splits in a single pass, or `jax.lax.scan` when memory is tight — it unrolls folds sequentially without materializing all intermediate states. Fold masks can be built with `jnp.arange(n) % k == fold_id`, keeping split logic functional and reproducible under `jax.random.PRNGKey`. All metric functions should be pure — no mutation — so they compose cleanly with `vmap` and remain XLA-traceable.$escape$,
  $escape$import jax
import jax.numpy as jnp
from functools import partial

@jax.jit
def confusion_matrix(y_true, y_pred, num_classes):
    return jnp.zeros((num_classes, num_classes)).at[y_true, y_pred].add(1)

@jax.jit
def precision_recall_f1(cm):
    tp = jnp.diag(cm)
    fp = cm.sum(axis=0) - tp
    fn = cm.sum(axis=1) - tp
    p = tp / (tp + fp + 1e-8)
    r = tp / (tp + fn + 1e-8)
    f1 = 2 * p * r / (p + r + 1e-8)
    return p, r, f1

def kfold_eval(X, y, model_fn, k=5):
    n = X.shape[0]
    def eval_fold(fold_id):
        mask = jnp.arange(n) % k == fold_id
        X_val, y_val = X[mask], y[mask]
        X_tr, y_tr = X[~mask], y[~mask]
        preds = model_fn(X_tr, y_tr, X_val)
        return jnp.mean(preds == y_val)
    return jax.vmap(eval_fold)(jnp.arange(k))$escape$,
  $escape$python$escape$,
