INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '37ba1d67-c3df-4d53-ba29-15f3f6e3ede1',
  '00000000-0000-0000-0000-000000000001',
  $escape$JAX + scikit-learn — Plug JAX Models into Pipeline, CV, and GridSearchCV$escape$,
  $escape$JAX arrays implement `__array__`, making them numpy-compatible — but sklearn's Pipeline still expects estimators that return numpy arrays. The unlock: wrap your JAX model as an sklearn estimator by subclassing `BaseEstimator` and `ClassifierMixin`. This gives you `Pipeline`, `StandardScaler`, `cross_val_score`, and `GridSearchCV` for free.

In `fit()`, cast inputs to `jnp.array`, build a JIT-compiled grad function with `jax.jit(jax.grad(...))`, and run your update loop. In `predict()`, cast DeviceArrays back with `np.array(...)` — sklearn internals will break on DeviceArrays during scoring. `get_params()` and `set_params()` are inherited from `BaseEstimator`, so `GridSearchCV` can sweep `lr` or `epochs` with zero extra code.

Let sklearn own the preprocessing layer — `StandardScaler` in the `Pipeline` normalizes before your JAX model sees data, so you avoid reimplementing normalization in JAX. `cross_val_score` handles fold splits, refitting, and metric aggregation automatically. This keeps JAX focused on what it does best — `jit`, `grad`, `vmap` — while delegating CV infrastructure to sklearn rather than rewriting k-fold logic as JAX primitives.$escape$,
  $escape$import jax, jax.numpy as jnp, numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.model_selection import cross_val_score

class JAXLogisticRegressor(BaseEstimator, ClassifierMixin):
    def __init__(self, lr=0.1, epochs=200):
        self.lr, self.epochs = lr, epochs
    def fit(self, X, y):
        X, y = jnp.array(X), jnp.array(y, float)
        p = jnp.zeros(X.shape[1] + 1)
        loss = lambda p: jnp.mean(jnp.log(1 + jnp.exp(-(2*y-1)*(X @ p[:-1] + p[-1]))))
        grad_fn = jax.jit(jax.grad(loss))
        for _ in range(self.epochs):
            p -= self.lr * grad_fn(p)
        self.w_, self.b_ = p[:-1], p[-1]; return self
    def predict(self, X):
        return np.array(jax.nn.sigmoid(jnp.array(X) @ self.w_ + self.b_) > 0.5, int)

pipe = Pipeline([("scale", StandardScaler()), ("clf", JAXLogisticRegressor())])
print(cross_val_score(pipe, X, y, cv=5).mean())$escape$,
  $escape$python$escape$,
